INSERT [dbo].[BlogPosts] ([BlogPostID], [Title], [Slug], [Excerpt], [Content], [CoverImageUrl], [IsPublished], [PublishedAt], [CreatedAt], [UpdatedAt], [ViewCount]) VALUES (2, N'Hiểu về Đất: Nền tảng của sự sống và nông nghiệp hữu cơ', N'hieu-ve-dat-nen-tang-cua-su-song-và-nong-nghiep-huu-co', N'Đất không chỉ là bụi bẩn, đất là một hệ sinh thái kỳ diệu.', N'<p class="text-xl font-medium text-on-surface leading-snug" style="--tw-border-spacing-x: 0; --tw-border-spacing-y: 0; --tw-translate-x: 0; --tw-translate-y: 0; --tw-rotate: 0; --tw-skew-x: 0; --tw-skew-y: 0; --tw-scale-x: 1; --tw-scale-y: 1; --tw-pan-x: ; --tw-pan-y: ; --tw-pinch-zoom: ; --tw-scroll-snap-strictness: proximity; --tw-gradient-from-position: ; --tw-gradient-via-position: ; --tw-gradient-to-position: ; --tw-ordinal: ; --tw-slashed-zero: ; --tw-numeric-figure: ; --tw-numeric-spacing: ; --tw-numeric-fraction: ; --tw-ring-inset: ; --tw-ring-offset-width: 0px; --tw-ring-offset-color: #fff; --tw-ring-color: rgb(59 130 246 / 0.5); --tw-ring-offset-shadow: 0 0 #0000; --tw-ring-shadow: 0 0 #0000; --tw-shadow: 0 0 #0000; --tw-shadow-colored: 0 0 #0000; --tw-blur: ; --tw-brightness: ; --tw-contrast: ; --tw-grayscale: ; --tw-hue-rotate: ; --tw-invert: ; --tw-saturate: ; --tw-sepia: ; --tw-drop-shadow: ; --tw-backdrop-blur: ; --tw-backdrop-brightness: ; --tw-backdrop-contrast: ; --tw-backdrop-grayscale: ; --tw-backdrop-hue-rotate: ; --tw-backdrop-invert: ; --tw-backdrop-opacity: ; --tw-backdrop-saturate: ; --tw-backdrop-sepia: ; --tw-contain-size: ; --tw-contain-layout: ; --tw-contain-paint: ; --tw-contain-style: ; border-width: 0px; border-style: solid; border-color: rgb(229, 231, 235); margin-top: 0px; margin-bottom: 0px; font-size: 1.25rem; line-height: 1.375; font-weight: 500; --tw-text-opacity: 1; color: rgb(26, 28, 28); font-family: Manrope; background-color: rgb(250, 249, 248);">Đất không chỉ là một lớp vật chất tĩnh lặng dưới chân chúng ta. Nó là một hệ sinh thái sống động, một thực thể thở, nơi hàng tỷ