INSERT [dbo].[Products] ([ProductID], [ProductName], [CategoryID], [SupplierID], [Price], [StockQuantity], [Unit], [Description], [CreatedAt], [DiscountPrice], [Sku], [ManufacturedDate], [ExpiryDate], [Origin], [StorageInstructions], [Certifications], [Status]) VALUES (41, N'Combo Nấu Canh Gia Đình', 9, 2, CAST(70000.00 AS Decimal(18, 2)), 7, N'Combo (2kg)', N'Combo rau củ tươi sạch gồm cà rốt, khoai tây, củ cải trắng, hành tây, cà chua và hành lá, rau mùi – tất cả được chọn lọc kỹ lưỡng để đảm bảo độ tươi ngon và dinh dưỡng. Sản phẩm phù hợp để chế biến các món canh, hầm xương hoặc nấu súp cho gia đình từ 3–5 người. Rau củ có vị ngọt tự nhiên, giúp món ăn đậm đà hơn mà không cần nhiều gia vị.', CAST(N'2026-04-08T06:59:55.353' AS DateTime), CAST(60000.00 AS Decimal(18, 2)), N'FF-COMBONAU-041', CAST(N'2026-04-13T09:28:42.8333333' AS DateTime2), CAST(N'2026-04-16T09:28:42.8333333' AS DateTime2), N'FreshFood Việt Nam', N'Bảo quản lạnh, dùng sớm', N'Đảm bảo VSATTP', N'Active')
INSERT [dbo].[Products] ([ProductID], [ProductName], [CategoryID], [SupplierID], [Price], [StockQuantity], [Unit], [Description], [CreatedAt], [DiscountPrice], [Sku], [ManufacturedDate], [ExpiryDate], [Origin], [StorageInstructions], [Certifications], [Status]) VALUES (42, N'Combo Salad Eat Clean', 9, 2, CAST(66000.00 AS Decimal(18, 2)), 33, N'combo (1.2kg)', N'Combo bao gồm xà lách tươi, cà chua bi, dưa leo, ớt chuông, bắp ngọt và cà rốt – đều là những nguyên liệu giàu vitamin, chất xơ và ít calo. Rau được chọn loại tươi, sạch, phù hợp ăn sống hoặc làm salad. Đây là lựa chọn lý tưởng cho người ăn kiêng, tập gym hoặc theo chế độ eat clean, giúp hỗ trợ giảm cân và làm đẹp da.', CAST(N'2026-04-08T07:48:10.940' AS DateTime), CAST(55000.00 AS Decimal(18, 2)), N'FF-COMBOSAL-042', CAST(N'2026-04-13T09:28:42.8333333' AS DateTime2), CAST(N'2026-04-16T09:28:42.8333333' AS DateTime2), N'FreshFood Việt Nam', N'Bảo quản lạnh, dùng sớm', N'Đảm bảo VSATTP', N'Active')
INSERT [dbo].[Products] ([ProductID], [ProductName], [CategoryID], [SupplierID], [Price], [StockQuantity], [Unit], [Description], [CreatedAt], [DiscountPrice], [Sku], [ManufacturedDate], [ExpiryDate], [Origin], [StorageInstructions], [Certifications], [Status]) VALUES (43, N'Combo Nước Ép Detox', 9, 2, CAST(120000.00 AS Decimal(18, 2)), 95, N'combo (2.5kg)', N'Combo trái cây và rau củ gồm táo, cam, cà rốt, dưa leo, cần tây và gừng – kết hợp hoàn hảo để ép nước hoặc làm sinh tố detox. Các nguyên liệu giàu vitamin C, chất chống oxy hóa và khoáng chất giúp thanh lọc cơ thể, tăng cường sức đề kháng và hỗ trợ tiêu hóa. Phù hợp sử dụng hằng ngày để duy trì lối sống lành mạnh.', CAST(N'2026-04-08T07:50:33.107' AS DateTime), CAST(100000.00 AS Decimal(18, 2)), N'FF-COMBONUO-043', CAST(N'2026-04-13T09:28:42.8333333' AS DateTime2), CAST(N'2026-04-16T09:28:42.8333333' AS DateTime2), N'FreshFood Việt Nam', N'Bảo quản lạnh, dùng sớm', N'Đảm bảo VSATTP', N'Active')
INSERT [dbo].[Products] ([ProductID], [ProductName], [CategoryID], [SupplierID], [Price], [StockQuantity], [Unit], [Description], [CreatedAt], [DiscountPrice], [Sku], [ManufacturedDate], [ExpiryDate], [Origin], [StorageInstructions], [Certifications], [Status]) VALUES (44, N'Combo "Đại Dương Thịnh Vượng"', 10, 3, CAST(3000000.00 AS Decimal(18, 2)), 22, N'combo (2.5kg - 3.0kg)', N'Sự kết hợp đẳng cấp giữa các loại hải sản nhập khẩu và đặc sản cao cấp, phù hợp cho các buổi tiệc gia đình quan trọng hoặc tiếp đãi đối tác. Hải sản được chế biến sốt bơ tỏi hoặc hấp rượu vang trắng. Thành phần: * 1 con Tôm hùm Alaska.

2 con Cua Cà Mau (loại 1).

Vẹm xanh New Zealand và Sò điệp Nhật.', CAST(N'2026-04-10T04:32:06.643' AS DateTime), CAST(2850000.00 AS Decimal(18, 2)), N'FF-COMBODAI-044', CAST(N'2026-04-13T09:28:42.8333333' AS DateTime2), CAST(N'2026-04-18T09:28:42.8333333' AS DateTime2), N'Việt Nam', N'Đông lạnh', N'HACCP', N'Active')
INSERT [dbo].[Products] ([ProductID], [ProductName], [CategoryID], [SupplierID], [Price], [StockQuantity], [Unit], [Description], [CreatedAt], [DiscountPrice], [Sku], [ManufacturedDate], [ExpiryDate], [Origin], [StorageInstructions], [Certifications], [Status]) VALUES (45, N'Combo "Gió Biển Miền Trung"', 10, 3, CAST(1400000.00 AS Decimal(18, 2)), 26, N'combo 2.2kg', N'Tập trung vào các loại hải sản đặc trưng của vùng biển Việt Nam với hương vị đậm đà. Phù hợp cho nhóm bạn nhậu hoặc họp mặt cuối tuần. Đi kèm là các loại nước chấm muối ớt xanh đặc sản.

Thành phần: * 500g Tôm sú loại lớn.

1kg Ốc hương (size trung).

500g Mực lá tươi (nướng hoặc hấp).

1 đĩa Hàu nướng mỡ hành (6 con).', CAST(N'2026-04-10T04:33:50.677' AS DateTime), CAST(1200000.00 AS Decimal(18, 2)), N'FF-COMBOGIO-045', CAST(N'2026-04-12T00:00:00.0000000' AS DateTime2), CAST(N'2026-04-17T00:00:00.0000000' AS DateTime2), N'Nguồn hải sản được khai thác từ các vùng biển sạch tại Việt Nam (miền Trung), nơi có môi trường nước trong lành và giàu dinh dưỡng, giúp hải sản có thịt chắc, vị ngọt tự nhiên.', N'Bảo quản sản phẩm ở nhiệt độ -18°C hoặc trong ngăn đông tủ lạnh để duy trì độ tươi ngon và kết cấu thịt hải sản.
Khi cần sử dụng, nên rã đông tự nhiên trong ngăn mát (0–4°C) từ 4–6 giờ hoặc qua đêm để giữ trọn hương vị.
Có thể rã đông nhanh bằng cách ngâm túi kín trong nước lạnh, tránh dùng nước nóng hoặc để ngoài nhiệt độ phòng quá lâu.
Không tái cấp đông sau khi đã rã đông để tránh mất chất dinh dưỡng và làm giảm chất lượng sản phẩm.
Sau khi mở bao bì, nên sử dụng trong vòng 24 giờ để đảm bảo độ tươi và an toàn thực phẩm.
Tránh để sản phẩm tiếp xúc trực tiếp với không khí trong thời gian dài, nên bọc kín hoặc dùng hộp đựng thực phẩm chuyên dụng.', N'HACCP', N'Active')
