INSERT [dbo].[ReturnRequests] ([ReturnRequestID], [OrderID], [UserID], [Status], [Reason], [AdminNote], [CreatedAt], [ReviewedAt], [VideoUrl], [RefundProofUrl], [RefundNote], [RequestType]) VALUES (4, 16, 6, N'Approved', N'Tôi muốn gửi yêu cầu hoàn hàng cho đơn hàng gồm các sản phẩm:
Khoai tây Đà Lạt, Cà rốt hữu cơ, Xoài cát Hòa Lộc, Thanh long Bình Thuận, Hành tây trắng và Chuối Laba Đà Lạt.

Lý do hoàn hàng:
Một số sản phẩm có dấu hiệu không đảm bảo độ tươi, cụ thể rau củ bị héo và trái cây có dấu hiệu chín quá, không đúng như chất lượng mô tả.

Mô tả chi tiết:
Sau khi nhận hàng và kiểm tra, tôi nhận thấy chất lượng sản phẩm không đồng đều, một số mặt hàng không còn tươi mới và không thể sử dụng lâu dài. Điều này ảnh hưởng đến trải nghiệm mua sắm của tôi.

Tôi mong muốn được hoàn hàng và hoàn tiền cho đơn hàng này.

Thông tin hoàn tiền:

Phương thức thanh toán: Chuyển khoản / VNPAY
Phương thức hoàn tiền: Chuyển khoản ngân hàng
